from __future__ import annotations

import argparse
import copy
import json
import sys
from pathlib import Path
import xml.etree.ElementTree as ET


NS = {"w": "http://schemas.openxmlformats.org/wordprocessingml/2006/main"}
W = "{" + NS["w"] + "}"


def qn(local: str) -> str:
    return f"{W}{local}"


def iter_word_xml(word_dir: Path) -> list[Path]:
    files: list[Path] = []
    for p in word_dir.rglob("*.xml"):
        name = p.name.lower()
        if name.startswith("comments"):
            continue
        files.append(p)
    return files


def count_tracked_changes(root: ET.Element) -> int:
    return sum(1 for _ in root.iter(qn("ins"))) + sum(1 for _ in root.iter(qn("del")))


def normalize_deleted_content(elem: ET.Element) -> None:
    if elem.tag == qn("delText"):
        elem.tag = qn("t")
    elif elem.tag == qn("delInstrText"):
        elem.tag = qn("instrText")
    for child in list(elem):
        normalize_deleted_content(child)


def resolve_change(elem: ET.Element, target_author: str, mode: str) -> list[ET.Element] | None:
    author = elem.attrib.get(qn("author"), "")
    if author != target_author:
        return None

    if elem.tag == qn("ins"):
        if mode == "accept":
            return [copy.deepcopy(c) for c in list(elem)]
        return []

    if elem.tag == qn("del"):
        if mode == "accept":
            return []
        restored = [copy.deepcopy(c) for c in list(elem)]
        for c in restored:
            normalize_deleted_content(c)
        return restored

    return None


def apply_author_resolution(parent: ET.Element, counters: dict[str, int]) -> None:
    i = 0
    while i < len(parent):
        child = parent[i]
        replacement = None

        if child.tag in (qn("ins"), qn("del")):
            replacement = resolve_change(child, "Alice", "accept")
            if replacement is not None:
                counters["alice"] += 1
            else:
                replacement = resolve_change(child, "Bob", "reject")
                if replacement is not None:
                    counters["bob"] += 1

        if replacement is not None:
            parent.remove(child)
            for offset, node in enumerate(replacement):
                parent.insert(i + offset, node)
            i += len(replacement)
            continue

        apply_author_resolution(child, counters)
        i += 1


def next_comment_id(comments_xml: Path) -> int:
    if not comments_xml.exists():
        return 0
    root = ET.parse(comments_xml).getroot()
    max_id = -1
    for c in root.findall(".//w:comment", NS):
        cid = c.attrib.get(qn("id"))
        if cid is None:
            continue
        try:
            max_id = max(max_id, int(cid))
        except ValueError:
            pass
    return max_id + 1


def add_comment_markers_to_first_paragraph(document_xml: Path, comment_id: int) -> None:
    tree = ET.parse(document_xml)
    root = tree.getroot()
    paragraph = root.find(".//w:body/w:p", NS)
    if paragraph is None:
        paragraph = root.find(".//w:p", NS)
    if paragraph is None:
        raise RuntimeError("No paragraph found in document.xml")

    start = ET.Element(qn("commentRangeStart"), {qn("id"): str(comment_id)})
    end = ET.Element(qn("commentRangeEnd"), {qn("id"): str(comment_id)})

    paragraph.insert(0, start)
    paragraph.append(end)

    ref_run = ET.Element(qn("r"))
    rpr = ET.SubElement(ref_run, qn("rPr"))
    ET.SubElement(rpr, qn("rStyle"), {qn("val"): "CommentReference"})
    ET.SubElement(ref_run, qn("commentReference"), {qn("id"): str(comment_id)})
    paragraph.append(ref_run)

    ET.register_namespace("w", NS["w"])
    tree.write(document_xml, encoding="utf-8", xml_declaration=True)


def main() -> None:
    parser = argparse.ArgumentParser()
    parser.add_argument("--unpacked", required=True)
    parser.add_argument("--stats", required=True)
    args = parser.parse_args()

    unpacked = Path(args.unpacked)
    word_dir = unpacked / "word"
    if not word_dir.exists():
        raise RuntimeError(f"Missing word directory: {word_dir}")

    xml_files = iter_word_xml(word_dir)
    total = 0
    parsed: list[tuple[Path, ET.ElementTree]] = []
    for p in xml_files:
        tree = ET.parse(p)
        root = tree.getroot()
        total += count_tracked_changes(root)
        parsed.append((p, tree))

    counters = {"alice": 0, "bob": 0}
    for p, tree in parsed:
        root = tree.getroot()
        apply_author_resolution(root, counters)
        ET.register_namespace("w", NS["w"])
        tree.write(p, encoding="utf-8", xml_declaration=True)

    remaining = 0
    for p in xml_files:
        root = ET.parse(p).getroot()
        remaining += count_tracked_changes(root)

    repo_root = Path(__file__).resolve().parents[2]
    comment_script_dir = repo_root / ".opencode" / "skills" / "docx" / "scripts"
    sys.path.insert(0, str(comment_script_dir))
    from comment import add_comment  # type: ignore

    comments_xml = word_dir / "comments.xml"
    comment_id = next_comment_id(comments_xml)
    add_comment(
        str(unpacked),
        comment_id,
        "Reviewed by agent — Alice accepted, Bob rejected.",
    )
    add_comment_markers_to_first_paragraph(word_dir / "document.xml", comment_id)

    stats = {
        "TotalTrackedChanges": total,
        "AliceChangesAccepted": counters["alice"],
        "BobChangesRejected": counters["bob"],
        "RemainingChanges": remaining,
    }
    Path(args.stats).parent.mkdir(parents=True, exist_ok=True)
    Path(args.stats).write_text(json.dumps(stats), encoding="utf-8")


if __name__ == "__main__":
    main()

